from itertools import combinations
from math import gcd
from functools import lru_cache

def maxScore(nums):
    n = len(nums) // 2
    @lru_cache(None)
    def dfs(mask, i):
        if mask == (1 << (2 * n)) - 1:
            return 0
        res = 0
        for x, y in combinations(range(2 * n), 2):
            if not (mask & (1 << x)) and not (mask & (1 << y)):
                res = max(res, i * gcd(nums[x], nums[y]) + dfs(mask | (1 << x) | (1 << y), i + 1))
        return res
    return dfs(0, 1)
